pub(crate) fn __logos_count_window_matches(
    haystack: &[u8],
    needle: &[u8],
    start: usize,
    end: usize,
) -> i64 {
    let m = needle.len();
    if m == 0 || haystack.len() < m {
        return 0;
    }
    let last = haystack.len() - m; // last valid start position (inclusive)
    let lo = start.min(last + 1);
    let hi = end.min(last + 1);
    if lo >= hi {
        return 0;
    }
